fn sanitize_path(path: &str) -> Option<String> {
    // Reject paths with null bytes
    if path.contains('\0') {
        return None;
    }

    // Normalize the path to prevent directory traversal
    let normalized = path
        .split('/')
        .filter(|segment| !segment.is_empty() && *segment != "." && *segment != "..")
        .collect::<Vec<&str>>()
        .join("/");

    let normalized = format!("/{}", normalized);

    // Validate path contains only allowed characters
    if !normalized
        .chars()
        .all(|c| c.is_ascii_alphanumeric() || c == '/' || c == '-' || c == '_' || c == '.' || c == '~')
    {
        return None;
    }

    // Limit path length
    if normalized.len() > 2048 {
        return None;
    }

    Some(normalized)
}

fn validate_method(method: &Method) -> bool {
    matches!(
        *method,
        Method::GET | Method::POST | Method::PUT | Method::DELETE | Method::HEAD | Method::OPTIONS
    )
}

fn find_route<'a>(path: &str, configs: &'a HashMap<&str, BackendConfig>) -> Option<&'a BackendConfig> {
    // Match the longest prefix first for specificity
    let mut best_match: Option<(&str, &BackendConfig)> = None;

    for (prefix, config) in configs.iter() {
        if path.starts_with(prefix) {
            match best_match {
                None => best_match = Some((prefix, config)),
                Some((current_prefix, _)) => {
                    if prefix.len() > current_prefix.len() {
                        best_match = Some((prefix, config));
                    }
                }
            }
        }
    }

    best_match.map(|(_, config)| config)
}

fn validate_backend_name(name: &str) -> bool {
    ALLOWED_BACKENDS.contains(&name)
}

fn create_backend(config: &BackendConfig) -> Result<Backend, Error> {
    if !validate_backend_name(config.name) {
        return Err(Error::msg("Invalid backend name"));
    }

    if !config.use_tls {
        return Err(Error::msg("TLS is required for all backend connections"));
    }

    let mut builder = Backend::builder(config.name, config.host)
        .override_host(config.host)
        .port(config.port)
        .connect_timeout(Duration::from_millis(config.connect_timeout_ms))
        .first_byte_timeout(Duration::from_millis(config.first_byte_timeout_ms))
        .between_bytes_timeout(Duration::from_millis(config.between_bytes_timeout_ms));

    // Always enable TLS with SNI
    builder = builder
        .enable_ssl()
        .ssl_min_version(fastly::backend::SslVersion::TLS1_2)
        .sni_hostname(config.sni_hostname)
        .cert_hostname(config.sni_hostname)
        .check_cert(true);

    builder.finish()
}

fn strip_sensitive_headers(req: &mut Request) {
    // Remove headers that should not be forwarded to backends
    let headers_to_remove = [
        "x-forwarded-for",
        "x-real-ip",
        "cf-connecting-ip",
        "true-client-ip",
        "x-debug",
        "x-internal-token",
    ];

    for header_name in &headers_to_remove {
        if let Ok(name) = header::HeaderName::from_bytes(header_name.as_bytes()) {
            req.remove_header(name);
        }
    }
}

fn add_security_headers(resp: &mut Response) {
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-XSS-Protection", "1; mode=block");
    resp.set_header("Strict-Transport-Security", "max-age=31536000; includeSubDomains");
    resp.set_header("Referrer-Policy", "strict-origin-when-cross-origin");
    resp.set_header(
        "Content-Security-Policy",
        "default-src 'self'; script-src 'self'; style-src 'self'",
    );
    resp.set_header(
        "Permissions-Policy",
        "geolocation=(), microphone=(), camera=()",
    );

    // Remove server identification headers from backend
    resp.remove_header("Server");
    resp.remove_header("X-Powered-By");
    resp.remove_header("X-AspNet-Version");
}

fn error_response(status: StatusCode, message: &str) -> Response {
    let mut resp = Response::from_status(status).with_body_text_plain(message);
    add_security_headers(&mut resp);
    resp
}

fn handle_request(mut req: Request) -> Result<Response, Error> {
    // Validate HTTP method
    if !validate_method(&req.get_method()) {
        return Ok(error_response(
            StatusCode::METHOD_NOT_ALLOWED,
            "Method not allowed",
        ));
    }

    // Validate and sanitize the request path
    let original_path = req.get_path().to_string();
    let sanitized_path = match sanitize_path(&original_path) {
        Some(path) => path,
        None => {
            return Ok(error_response(StatusCode::BAD_REQUEST, "Invalid request path"));
        }
    };

    // Validate request body size for methods that have bodies
    if matches!(*req.get_method(), Method::POST | Method::PUT) {
        if let Some(content_length) = req.get_header_str("content-length") {
            if let Ok(length) = content_length.parse::<usize>() {
                if length > MAX_REQUEST_BODY_SIZE {
                    return Ok(error_response(
                        StatusCode::PAYLOAD_TOO_LARGE,
                        "Request body too large",
                    ));
                }
            }
        }
    }

    // Validate Host header exists and is reasonable
    let host = req.get_header_str("host").unwrap_or("");
    if host.is_empty() || host.len() > 253 {
        return Ok(error_response(StatusCode::BAD_REQUEST, "Invalid Host header"));
    }

    // Strip sensitive headers before forwarding
    strip_sensitive_headers(&mut req);

    // Find the appropriate backend based on the route
    let configs = get_backend_configs();
    let backend_config = match find_route(&sanitized_path, &configs) {
        Some(config) => config,
        None => {
            return Ok(error_response(StatusCode::NOT_FOUND, "Not found"));
        }
    };

    // Create the backend connection with TLS
    let backend = match create_backend(backend_config) {
        Ok(b) => b,
        Err(_) => {
            return Ok(error_response(
                StatusCode::BAD_GATEWAY,
                "Backend configuration error",
            ));
        }
    };

    // Set the sanitized path back on the request
    req.set_path(&sanitized_path);

    // Add a request ID for tracing (without exposing internal details)
    let request_id = fastly::handle::RequestHandle::new();
    // Use a simple counter-based approach; in production you'd use a proper UUID
    req.set_header("X-Request-ID", format!("{:?}", request_id));

    // Forward the request to the backend
    match req.send(backend) {
        Ok(mut resp) => {
            // Add security headers to the response
            add_security_headers(&mut resp);

            // Ensure we don't leak backend error details to clients
            let status = resp.get_status();
            if status.is_server_error() {
                // Log the actual error internally but return a generic message
                // In production, use a proper logging mechanism
                return Ok(error_response(
                    StatusCode::BAD_GATEWAY,
                    "An error occurred while processing your request",
                ));
            }

            Ok(resp)
        }
        Err(_) => Ok(error_response(
            StatusCode::BAD_GATEWAY,
            "Unable to connect to backend",
        )),
    }
}

